 	if tmuxEnv := os.Getenv("TMUX"); tmuxEnv != "" {
 		// $TMUX format: /path/to/socket,server_pid,session_index
 		if socketPath, _, ok := strings.Cut(tmuxEnv, ","); ok && socketPath != "" {
 			tmux.SetDefaultSocket(filepath.Base(socketPath))
 		}
